export default class BossLogic {
  constructor() {
    this.jumpTimer = 0;
  }
  update(dt) {
    this.jumpTimer += dt;
    if (this.jumpTimer > 2.5) {
      const rb = this.entity.getComponent('RigidBody');
      if (rb && rb.velocity) {
        rb.velocity.y = -500;
      }
      this.jumpTimer = 0;
    }
  }
}

